        return None

    def save_cache(self, index_name, cache_data):
        cache_file = self.get_cache_file(index_name)
        with open(cache_file, "wb") as f:
            pickle.dump(cache_data, f)

    def delete_cache(self, index_name):
        cache_file = self.get_cache_file(index_name)
        if os.path.exists(cache_file):
            os.remove(cache_file)
